import React, { useState, useEffect } from 'react';
import api from '../api';

const AnalyticsDashboard = () => {
  const [analytics, setAnalytics] = useState(null);
  const [year, setYear] = useState(2024);
  const [month, setMonth] = useState(1);

  useEffect(() => {
    fetchAnalytics();
  }, [year, month]);

  const fetchAnalytics = async () => {
    try {
      const res = await api.get(`/analytics/monthly?year=${year}&month=${month}`);
      setAnalytics(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  if (!analytics) return <div className="flex items-center justify-center p-12 text-indigo-500 font-bold animate-pulse text-xl">Loading metrics...</div>;

  return (
    <div className="bg-white rounded-3xl shadow-2xl p-10 h-full">
      <div className="flex justify-between items-center mb-8">
        <h3 className="text-3xl font-black text-gray-900">Financial Health</h3>
        <div className="flex items-center space-x-3 bg-gray-50 p-2 rounded-2xl border border-gray-100">
          <input type="number" value={year} onChange={(e) => setYear(e.target.value)} className="w-24 p-3 bg-white border-2 border-transparent focus:border-indigo-300 rounded-xl font-bold outline-none shadow-sm" />
          <input type="number" min="1" max="12" value={month} onChange={(e) => setMonth(e.target.value)} className="w-20 p-3 bg-white border-2 border-transparent focus:border-indigo-300 rounded-xl font-bold outline-none shadow-sm" />
          <button onClick={fetchAnalytics} className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-bold shadow-md hover:bg-indigo-700 hover:shadow-lg transition-all">Update</button>
        </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-gradient-to-br from-emerald-400 to-teal-600 text-white p-8 rounded-3xl shadow-xl text-center transform hover:scale-105 transition-transform duration-300">
          <h3 className="text-lg font-bold opacity-90 mb-3 tracking-wide uppercase">Savings Rate</h3>
          <p className="text-5xl font-black">{parseFloat(analytics.savingsRate || 0).toFixed(1)}%</p>
        </div>
        <div className="bg-gradient-to-br from-indigo-400 to-blue-600 text-white p-8 rounded-3xl shadow-xl text-center transform hover:scale-105 transition-transform duration-300">
          <h3 className="text-lg font-bold opacity-90 mb-3 tracking-wide uppercase">Expense Volatility</h3>
          <p className="text-5xl font-black">${parseFloat(analytics.expenseStd || 0).toFixed(0)}</p>
        </div>
        <div className="bg-gradient-to-br from-orange-400 to-red-600 text-white p-8 rounded-3xl shadow-xl text-center transform hover:scale-105 transition-transform duration-300">
          <h3 className="text-lg font-bold opacity-90 mb-3 tracking-wide uppercase">Budget Usage</h3>
          <p className="text-5xl font-black">{(parseFloat(analytics.budgetUsage || 0) * 100).toFixed(1)}%</p>
        </div>
      </div>
    </div>
  );
};

export default AnalyticsDashboard;
